#include <bits/stdc++.h>
using namespace std;

const int N=2e6+100;

struct Node{
    int son[26],fail;
}tr[N];

int n,k,tot=1,idx[N],q[N],hh,tt,dfn[N],sz[N],num,sum[N];
char s[N];
vector<int> e[N];

void Insert(int x,int len){
    int p=1;
    for(int i=len;i;i--){
        if(!tr[p].son[s[i]-'A'])
            tr[p].son[s[i]-'A']=++tot;
        p=tr[p].son[s[i]-'A'];
    }
    idx[x]=p;
}

void build(){
    hh=1,tt=0;
    tr[1].fail=1;
    for(int i=0;i<26;i++)
        if(tr[1].son[i]){
            q[++tt]=tr[1].son[i];
            tr[tr[1].son[i]].fail=1;
        }else
            tr[1].son[i]=1;
    while(hh<=tt){
        int x=q[hh++];
        e[tr[x].fail].push_back(x);
        for(int i=0;i<26;i++)
            if(tr[x].son[i]){
                q[++tt]=tr[x].son[i];
                tr[tr[x].son[i]].fail=tr[tr[x].fail].son[i];
            }else
                tr[x].son[i]=tr[tr[x].fail].son[i];
    }
}

void dfs(int x){
    dfn[x]=++num;
    sz[x]=1;
    for(int y:e[x]){
        dfs(y);
        sz[x]+=sz[y];
    }
}

int main(){
    idx[0]=1;
    scanf("%d%d",&n,&k);
    for(int i=1,p;i<=n;i++){
        scanf("%s%d",s,&p);
        if(!tr[idx[p]].son[s[0]-'A'])
            tr[idx[p]].son[s[0]-'A']=++tot;
        idx[i]=tr[idx[p]].son[s[0]-'A'];
    }
    for(int i=1;i<=k;i++){
        scanf("%s",s+1);
        Insert(n+i,strlen(s+1));
    }
    build();
    dfs(1);
    for(int i=1;i<=n;i++)
        sum[dfn[idx[i]]]++;
    for(int i=1;i<=tot;i++)
        sum[i]+=sum[i-1];
    for(int i=1;i<=k;i++){
        int x=idx[n+i];
        printf("%d\n",sum[dfn[x]+sz[x]-1]-sum[dfn[x]-1]);
    }
    return 0;
}
